import{c as t,Q as s,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I suspend or reactivate a user?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/suspend-user.md","filePath":"guide/recipes/portal/suspend-user.md","lastUpdated":1779094756000}'),o={name:"guide/recipes/portal/suspend-user.md"};function i(n,e,l,d,u,c){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-suspend-or-reactivate-a-user" tabindex="-1">How do I suspend or reactivate a user? <a class="header-anchor" href="#how-do-i-suspend-or-reactivate-a-user" aria-label="Permalink to &quot;How do I suspend or reactivate a user?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>Suspending a user blocks their access without removing them. Their tenant assignments are preserved, so reactivation is one click.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="to-suspend" tabindex="-1">To suspend <a class="header-anchor" href="#to-suspend" aria-label="Permalink to &quot;To suspend&quot;">​</a></h3><ol><li>Open <strong>Users</strong> in the sidebar.</li><li>Click the row of the user.</li><li>Click <strong>Suspend User</strong> in the actions menu (top right of the expanded panel).</li><li>Confirm.</li></ol><h3 id="to-reactivate" tabindex="-1">To reactivate <a class="header-anchor" href="#to-reactivate" aria-label="Permalink to &quot;To reactivate&quot;">​</a></h3><ol><li>Filter the Users table by <strong>Status: Suspended</strong> (or just find the user).</li><li>Open their row.</li><li>Click <strong>Reactivate</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>Suspended users are signed out immediately and blocked from signing back in. The Users table shows them with a <strong>Suspended</strong> badge. Tenant assignments are retained — when you reactivate, they regain access to every tenant they were on.</p><div class="tip custom-block"><p class="custom-block-title">When to suspend vs. remove</p><ul><li><strong>Suspend</strong> when a user is on leave, has lost their device, or you&#39;re investigating something.</li><li><strong>Remove</strong> (different recipe) when the relationship has ended permanently.</li></ul></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./remove-user">How do I remove a user from my customer?</a></li><li><a href="./change-user-role">How do I change a user&#39;s portal role?</a></li></ul>',13)])])}const m=t(o,[["render",i]]);export{p as __pageData,m as default};
